把 `gzip.decompress().decode()` 移到线程里，最小改动如下（同时把 `errors="replace"` 加上更稳）：

```python
import gzip

def _gzip_decode(data: bytes, src_encoding: str) -> str:
    # 线程里做 CPU 解压 + 解码
    return gzip.decompress(data).decode(src_encoding, errors="replace")

async def fetch_one(s3_client, blob_id: str, src_encoding: str) -> dict:
    try:
        response = await s3_client.get_object(Bucket="softwareheritage", Key=f"content/{blob_id}")
        async with response["Body"] as stream:
            data = await stream.read()

        # 把 gzip 解压 + decode 放到线程池，避免阻塞事件循环
        text = await asyncio.to_thread(_gzip_decode, data, src_encoding)

    except Exception as e:
        print(f"\n[FATAL] Failed to fetch {blob_id}: {e}")
        if "NoSuchKey" in str(e):
            text = ""
        else:
            raise
    return {"blob_id": blob_id, "text": text}
```

